sql:
SELECT load_id, load_mw
FROM energy_loads
WHERE source_id = 0;

SELECT locations.location_name, energy_loads.date, energy_loads.hour
FROM energy_loads
INNER JOIN locations ON energy_loads.location_id = locations.location_id;

external_knowledge:
- "main site" refers to "Location1";
- "midday hour" refers to the 12th hour of the day;
- "typical power consumption" implies the average energy load in MW.

sql:
SELECT SUM(load_mw) AS total_load 
FROM energy_loads 
WHERE location_id = (SELECT location_id FROM locations WHERE location_name = 'Main Office');

SELECT location_id, hour, AVG(load_mw) AS average_load
FROM energy_loads
GROUP BY location_id, hour;

SELECT source_id, location_id
FROM forecasts
WHERE confidence_level > 0.8;

SELECT load_id, load_mw, location_id
FROM energy_loads
WHERE load_mw > (SELECT AVG(load_mw) FROM energy_loads);

SELECT DISTINCT notification_type 
FROM notifications 
WHERE severity = 'low';
